// ==UserScript==
// @name           Update SP CSC Favicon
// @version        1.0
// @description    Replaces SP CSC icon with something almost like the old one but much uglier.
// @match        https://vunl.sharepoint.com/sites/VU-IT-CS-CSC-VerhuizingenenProjecten*
// ==/UserScript==
window.addEventListener('load', function() {
    var favicon = document.querySelector('link[rel~="icon"]');
    var clone = favicon.cloneNode(!0);
    clone.href = "data:image/png;base64,";
    // template clone.href = "";
    favicon.parentNode.removeChild(favicon);
    document.head.appendChild(clone);
}, false);
